#include <algorithm>
#include <unordered_map>
#include <utility>

using namespace std;

int max_len = 0;

void dfs(int node, unordered_map<int, vector<int>>& graph, string& label, vector<bool>& visited, unordered_map<char, int>& char_count) {
    visited[node] = true;
    char c = label[node];
    char_count[c]++;

    int odd = 0, sum = 0;
    for (auto& p : char_count) {
        if (p.second % 2 == 1) {
            odd++;
        }
        sum += p.second;
    }

    if (odd <= 1) {
        max_len = max(max_len, sum);
    }

    for (int neighbor : graph[node]) {
        if (!visited[neighbor]) {
            dfs(neighbor, graph, label, visited, char_count);
        }
    }

    char_count[c]--;
    if (char_count[c] == 0) {
        char_count.erase(c);
    }
    visited[node] = false;
}

long long solve(long long n, std::vector<std::vector<long long>> edges, std::string label) {
    max_len = 0;
    unordered_map<int, vector<int>> graph;
    for (auto& edge : edges) {
        int u = edge[0];
        int v = edge[1];
        graph[u].push_back(v);
        graph[v].push_back(u);
    }

    for (int i = 0; i < n; ++i) {
        vector<bool> visited(n, false);
        unordered_map<char, int> char_count;
        dfs(i, graph, label, visited, char_count);
    }

    return max_len;
}
